import { readFile, writeFile } from "node:fs/promises";
import { createBucket, put, list } from "@tigrisdata/storage";

const TRIAL_ID_PATH = "/logs/artifacts/trial_id";
const LISTING_PATH = "/home/user/tigris-task/listing.txt";

const normalizeBucketName = (value: string) =>
  value
    .toLowerCase()
    .replace(/[^a-z0-9.-]/g, "-")
    .replace(/^-+/, "")
    .replace(/-+$/, "");

const getBucketName = (trialId: string) =>
  normalizeBucketName(`harbor-tssdk-${trialId}`);

const ensureBucket = async (bucketName: string) => {
  const { error } = await createBucket(bucketName);
  if (!error) {
    return;
  }

  if (error.message?.toLowerCase().includes("already")) {
    return;
  }

  throw error;
};

const uploadMessages = async (bucketName: string) => {
  const messages = [
    { key: "inbox/msg-1.json", body: "{\"id\": 1}" },
    { key: "inbox/msg-2.json", body: "{\"id\": 2}" },
    { key: "inbox/msg-3.json", body: "{\"id\": 3}" },
  ];

  for (const message of messages) {
    const { error } = await put(message.key, message.body, {
      config: { bucket: bucketName },
      metadata: { contentType: "application/json" },
    });

    if (error) {
      throw error;
    }
  }
};

const writeListing = async (bucketName: string) => {
  const { data, error } = await list({
    prefix: "inbox/",
    config: { bucket: bucketName },
  });

  if (error) {
    throw error;
  }

  const names = data?.items?.map((item) => item.name).filter(Boolean) ?? [];
  await writeFile(LISTING_PATH, names.join("\n"));
};

const run = async () => {
  const trialId = (await readFile(TRIAL_ID_PATH, "utf-8")).trim();
  const bucketName = getBucketName(trialId);

  if (!bucketName) {
    throw new Error("Bucket name resolved to an empty string.");
  }

  await ensureBucket(bucketName);
  await uploadMessages(bucketName);
  await writeListing(bucketName);
};

try {
  await run();
} catch (error) {
  console.error("Failed to complete Tigris workflow:", error);
  process.exit(1);
}
